class WSSecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final long TIMESTAMP_TOLERANCE_MS = 300000;
    
    private static final ConcurrentHashMap<String, Long> processedTimestamps = new ConcurrentHashMap<>();

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outbound) {
            return handleOutboundMessage(context);
        } else {
            return handleInboundMessage(context);
        }
    }

    private boolean handleOutboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                header = envelope.addHeader();
            }

            addTimestampToHeader(header);
            message.saveChanges();

            return true;
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    private boolean handleInboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                throw new SecurityException("Missing SOAP header with security information");
            }

            TimestampInfo timestampInfo = extractTimestampFromHeader(header);
            
            if (timestampInfo == null) {
                throw new SecurityException("Missing timestamp in security header");
            }

            validateTimestamp(timestampInfo);

            return true;
        } catch (SecurityException se) {
            System.err.println("Security validation failed: " + se.getMessage());
            return false;
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    private void addTimestampToHeader(SOAPHeader header) throws Exception {
        SOAPElement security = header.addChildElement("Security", "wsse", WSSE_NS);
        security.addNamespaceDeclaration("wsu", WSU_NS);

        SOAPElement timestamp = security.addChildElement("Timestamp", "wsu", WSU_NS);
        String timestampId = "TS-" + UUID.randomUUID().toString();
        timestamp.addAttribute(new QName(WSU_NS, "Id", "wsu"), timestampId);

        Date now = new Date();
        Date expires = new Date(now.getTime() + TIMESTAMP_TOLERANCE_MS);

        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));

        SOAPElement created = timestamp.addChildElement("Created", "wsu", WSU_NS);
        created.setTextContent(dateFormat.format(now));

        SOAPElement expiresElement = timestamp.addChildElement("Expires", "wsu", WSU_NS);
        expiresElement.setTextContent(dateFormat.format(expires));
    }

    private TimestampInfo extractTimestampFromHeader(SOAPHeader header) throws Exception {
        Iterator<?> securityElements = header.getChildElements(new QName(WSSE_NS, "Security"));

        if (!securityElements.hasNext()) {
            return null;
        }

        SOAPElement security = (SOAPElement) securityElements.next();
        Iterator<?> timestampElements = security.getChildElements(new QName(WSU_NS, "Timestamp"));

        if (!timestampElements.hasNext()) {
            return null;
        }

        SOAPElement timestamp = (SOAPElement) timestampElements.next();
        TimestampInfo info = new TimestampInfo();

        String timestampId = timestamp.getAttributeValue(new QName(WSU_NS, "Id"));
        info.setId(timestampId);

        Iterator<?> createdElements = timestamp.getChildElements(new QName(WSU_NS, "Created"));
        if (createdElements.hasNext()) {
            SOAPElement created = (SOAPElement) createdElements.next();
            info.setCreated(created.getTextContent());
        }

        Iterator<?> expiresElements = timestamp.getChildElements(new QName(WSU_NS, "Expires"));
        if (expiresElements.hasNext()) {
            SOAPElement expires = (SOAPElement) expiresElements.next();
            info.setExpires(expires.getTextContent());
        }

        return info;
    }

    private void validateTimestamp(TimestampInfo info) throws Exception {
        if (info.getCreated() == null) {
            throw new SecurityException("Timestamp Created element is missing");
        }

        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));

        Date createdDate = dateFormat.parse(info.getCreated());
        Date now = new Date();

        if (createdDate.getTime() > now.getTime() + TIMESTAMP_TOLERANCE_MS) {
            throw new SecurityException("Timestamp is from the future");
        }

        if (info.getExpires() != null) {
            Date expiresDate = dateFormat.parse(info.getExpires());
            if (now.getTime() > expiresDate.getTime()) {
                throw new SecurityException("Timestamp has expired");
            }
        } else {
            if (now.getTime() - createdDate.getTime() > TIMESTAMP_TOLERANCE_MS) {
                throw new SecurityException("Timestamp is too old");
            }
        }

        String timestampKey = info.getId() != null ? info.getId() : info.getCreated();
        if (processedTimestamps.containsKey(timestampKey)) {
            throw new SecurityException("Replay attack detected - timestamp already processed");
        }

        processedTimestamps.put(timestampKey, now.getTime());

        cleanupOldTimestamps();
    }

    private void cleanupOldTimestamps() {
        long cutoffTime = System.currentTimeMillis() - (TIMESTAMP_TOLERANCE_MS * 2);
        processedTimestamps.entrySet().removeIf(entry -> entry.getValue() < cutoffTime);
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, "Security"));
        return headers;
    }
}

